let countElement = document.querySelector('#count');
let increaseBtn = document.querySelector('#increase');
let decreaseBtn = document.querySelector('#decrease');
let resetBtn = document.querySelector('#reset');
let count = 0;
function updateCount() {
  countElement.textContent = count;
  if (count > 0) countElement.style.color = 'green';
  else if (count < 0) countElement.style.color = 'red';
  else countElement.style.color = '#c8d1dc';
}
increaseBtn.addEventListener('click', function() { count++; updateCount(); });
decreaseBtn.addEventListener('click', function() { count--; updateCount(); });
resetBtn.addEventListener('click', function() { count = 0; updateCount(); });

let taskInput = document.querySelector('#taskInput');
let addTask = document.querySelector('#addTask');
let taskList = document.querySelector('#taskList');
let clearAll = document.querySelector('#clearAll');

function addNewTask() {
  let taskText = taskInput.value.trim();
  if (taskText === '') {
    alert('اكتب مهمة الأول');
    return;
  }
  let li = document.createElement('li');
  let span = document.createElement('span');
  span.textContent = taskText;
  let deleteBtn = document.createElement('button');
  deleteBtn.textContent = 'Delete';
  deleteBtn.classList.add('delete-btn');
  li.appendChild(span);
  li.appendChild(deleteBtn);
  taskList.appendChild(li);
  taskInput.value = '';
}

addTask.addEventListener('click', addNewTask);
taskInput.addEventListener('keydown', function(event) {
  if (event.key === 'Enter') addNewTask();
});
taskList.addEventListener('click', function(event) {
  if (event.target.classList.contains('delete-btn')) {
    event.target.parentElement.remove();
  }
  if (event.target.tagName === 'SPAN') {
    event.target.classList.toggle('completed');
  }
});
clearAll.addEventListener('click', function() {
  taskList.innerHTML = '';
});
